extern char trampoline[], uservec[], userret[];

void kernelvec();

extern int devintr();
extern int user_devintr();
extern int kernel_devintr();
void trapinit(void)
{
  initlock(&tickslock, "time");
}

void trapinithart(void)
{
  w_stvec((uint64_t)kernelvec);
}

void usertrap(void)
{
  int which_dev = 0;

  if((r_sstatus() & SSTATUS_SPP) != 0)
    panic("usertrap: not from user mode");

  w_stvec((uint64_t)kernelvec);

  struct proc *p = myproc();

  p->trapframe->epc = r_sepc();

  if(r_scause() == 8){

    if(killed(p))
      exit(-1);

    p->trapframe->epc += 4;

    intr_on();

    syscall();
  } else if((which_dev = user_devintr()) != 0){
    // ok
  } else {
    /*
    printf("usertrap(): unexpected scause %p pid=%d\n", r_scause(), p->pid);
    printf("            sepc=%p stval=%p\n", r_sepc(), r_stval());
    */
    setkilled(p);
  }

  if(killed(p))
    exit(-1);

  if(which_dev == 2)
    yield();

  usertrapret();
}

void usertrapret(void)
{
  struct proc *p = myproc();

  intr_off();

  uint64_t trampoline_uservec = TRAMPOLINE + (uservec - trampoline);
  w_stvec(trampoline_uservec);

  p->trapframe->kernel_satp = r_satp();         
  p->trapframe->kernel_sp = p->kstack + PGSIZE; 
  p->trapframe->kernel_trap = (uint64_t)usertrap;
  p->trapframe->kernel_hartid = r_tp();    

  unsigned long x = r_sstatus();
  x &= ~SSTATUS_SPP; 
  x |= SSTATUS_SPIE; 
  w_sstatus(x);

  w_sepc(p->trapframe->epc);

  uint64_t satp = MAKE_SATP(p->pagetable);

  uint64_t trampoline_userret = TRAMPOLINE + (userret - trampoline);
  ((void (*)(uint64_t))trampoline_userret)(satp);
}

void kerneltrap()
{
  int which_dev = 0;
  uint64_t sepc = r_sepc();
  uint64_t sstatus = r_sstatus();
  uint64_t scause = r_scause();

  if((sstatus & SSTATUS_SPP) == 0)
    panic("kerneltrap: not from supervisor mode");
  if(intr_get() != 0)
    panic("kerneltrap: interrupts enabled");

  if((which_dev = kernel_devintr()) == 0){
    printf("scause %p\n", scause);
    printf("sepc=%p stval=%p\n", r_sepc(), r_stval());
    panic("kerneltrap");
  }

  // give up the CPU if this is a timer interrupt.
  if(which_dev == 2 && myproc() != 0 && myproc()->state == RUNNING)
    yield();

  // the yield() may have caused some traps to occur,
  // so restore trap registers for use by kernelvec.S's sepc instruction.
  w_sepc(sepc);
  w_sstatus(sstatus);
}

void
clockintr()
{
  acquire(&tickslock);
  ticks++;
  wakeup(&ticks);
  release(&tickslock);
}

uint32_t user_ticks;
uint32_t super_ticks;

void user_clockintr()
{
  acquire(&tickslock);
  user_ticks++;
  ticks++;
  wakeup(&user_ticks);
  release(&tickslock);
}

void super_clockintr()
{
  acquire(&tickslock);
  super_ticks++;
  ticks++;
  wakeup(&super_ticks);
  release(&tickslock);
}

void c_user_clockintr()
{
  ticks++;
}

void c_super_clockintr()
{
  ticks++;
}

int devintr()
{
  uint64_t scause = r_scause();

  if((scause & 0x8000000000000000L) &&
     (scause & 0xff) == 9){

    int irq = plic_claim();

    if(irq == Uart0_IRQ){
      uart_intr();
    } else if(irq == VIRTIO0_IRQ){
      virtio_disk_intr();
    } else if(irq){
      printf("unexpected interrupt irq=%d\n", irq);
    }

    if(irq)
      plic_complete(irq);

    return 1;
  } else if(scause == 0x8000000000000001L){

    if(cpuid() == 0){
      clockintr();
    }

    w_sip(r_sip() & ~2);

    return 2;
  } else {
    return 0;
  }
}

