extern char end[];

struct run{
    struct run *next;
};

struct {
    struct spinlock lock;
    struct run *freelist;
    uint64_t npage;
} kmem;

void kfree(void *pa){
    struct run *r;
    if(((uint64_t)pa % PGSIZE) != 0 || (char *)pa < end || (uint64_t)pa >= PHYSTOP){
        panic("kfree");
    }
    memset(pa, 1, PGSIZE);

    r = (struct run*)pa;

    acquire(&kmem.lock);
    r->next = kmem.freelist;
    kmem.freelist = r;
    kmem.npage++;
    release(&kmem.lock);
}

void kinit(){
    //printf("kinit\n");
    initlock(&kmem.lock, "kmem");
    freerange(end, (void *)PHYSTOP);
    //printf("kinit\n");
}

void freerange(void *pa_start, void *pa_end){
    char *p;
    p = (char *)PGROUNDUP((uint64_t) pa_start);
    for(; p + PGSIZE <= (char *)pa_end; p+= PGSIZE){
        kfree(p);
    }
}

void * kalloc(void)
{
    struct run *r;

    acquire(&kmem.lock);
    r = kmem.freelist;
    if(r) {
        kmem.freelist = r->next;
        kmem.npage--;
    }
    release(&kmem.lock);

    if(r)
        memset((char*)r, 5, PGSIZE);
    return (void*)r;
}

uint64_t freemem_amount(void)
{
  return kmem.npage << PGSHIFT;
}

