int flags2perm(int flags){
    int perm = 0;
    if(flags & 0x1){
        perm = PTE_X;
    }
    if(flags & 0x2){
        perm |= PTE_W;
    }
    return perm;
}

static int loadseg(pagetable_t pagetable, uint64_t va, struct dirent *ip, uint32_t offset, uint32_t sz){
    uint32_t i, n;
    uint64_t pa;

    for(i = 0; i < sz; i += PGSIZE){
        pa = walkaddr(pagetable, va + i);
        if(pa == 0){
            panic("loadseg: address should exist");
        }
        if(sz - i < PGSIZE){
            n = sz - i;
        } else {
            n = PGSIZE;
        }
        if(readi(ip, 0, (uint64_t)pa, offset + i, n) != n){
            return -1;
        }
    }
    return 0;
}

#define MAXARG 32
int exec(char *path, char **argv){
    //printf("path : %s\n", path);

    //printf("hello exec\n");
    char *s, *last;
    int i, off;
    uint64_t argc, sz = 0, sp, ustack[MAXARG + 1], stackbase;
    struct elfh elf;
    struct dirent *ip;
    struct proghdr ph;
    pagetable_t pagetable = 0, oldpagetable;
    struct proc *p = myproc();

    //printf("exec -1\n");
    /*
    printf("\n");
    for(int i = 0; argv[i] != 0; i++){
        printf("i : %d ", i);
    }
    printf("\n");  
    */

    if((ip = namei(path)) == 0){
        while(1);
        //printf("ip == 0\n");
        return -1;
    }

    ilock(ip);
    //printf("exec 0\n");
    if(readi(ip, 0, (uint64_t)&elf, 0, sizeof(elf)) != sizeof(elf) || elf.magic != ELF_MAGIC || (pagetable = proc_pagetable(p)) == 0){
        if(pagetable)
            proc_freepagetable(pagetable, sz);
        if(ip){
            iunlockput(ip);  
        }
        return -1;
    }
    //printf("exec 1\n");
    for(i = 0, off = elf.phoff; i < elf.phnum; i++, off += sizeof(ph)){
        if(readi(ip, 0, (uint64_t)&ph, off, sizeof(ph)) != sizeof(ph)){
            if(pagetable)
                proc_freepagetable(pagetable, sz);
            if(ip){
                iunlockput(ip);       
            }
            return -1;
        }

        if(ph.type != ELF_PROG_LOAD){
            continue;
        }
        if(ph.memsz < ph.filesz || ph.vaddr + ph.memsz < ph.vaddr || ph.vaddr % PGSIZE != 0){
            if(pagetable)
                proc_freepagetable(pagetable, sz);
            if(ip){
                iunlockput(ip);  
            }
            return -1;
        }

        uint64_t sz1;
        if((sz1 = uvmalloc(pagetable, sz, ph.vaddr + ph.memsz, flags2perm(ph.flags))) == 0){
            if(pagetable)
                proc_freepagetable(pagetable, sz);
            if(ip){
                iunlockput(ip);
            }
            return -1;
        }
        sz = sz1;
        if(loadseg(pagetable, ph.vaddr, ip, ph.off, ph.filesz) < 0){
            if(pagetable)
                proc_freepagetable(pagetable, sz);
            if(ip){
                iunlockput(ip);
            }
            return -1;
        }
    }
    //printf("exec 2\n");
    iunlockput(ip);

    ip = 0;

    p = myproc();
    uint64_t oldsz = p->sz;

    sz = PGROUNDUP(sz);
    uint64_t sz1;
    if((sz1 = uvmalloc(pagetable, sz, sz + 2 * PGSIZE, PTE_W)) == 0){
        if(pagetable)
                proc_freepagetable(pagetable, sz);
        if(ip){
            iunlockput(ip);
        }
        return -1;
    }

    sz = sz1;
    uvmclear(pagetable, sz-2*PGSIZE);
    sp = sz;
    stackbase = sp - PGSIZE;
    /*
    printf("exec argv: %d\n", argv[0] == 0);
    int j = 0;
    while(argv[j]){ j++; };
    printf("iii : %d\n", j);
    */
    for(argc = 0; argv[argc]; argc++){
        //printf("exec argc : %d\n", argc);
        if(argc >= MAXARG){
            if(pagetable)
                proc_freepagetable(pagetable, sz);
            if(ip){
                iunlockput(ip);
            }
            return -1;
        }
        sp -= strlen(argv[argc]) + 1;
        sp -= sp % 16;
        if(sp < stackbase){
            if(pagetable)
                proc_freepagetable(pagetable, sz);
            if(ip){
                iunlockput(ip);
            }
            return -1;
        }
        if(copyout(pagetable, sp, argv[argc], strlen(argv[argc]) + 1) < 0){
            if(pagetable)
                proc_freepagetable(pagetable, sz);
            if(ip){
                iunlockput(ip);
            }
            return -1;
        }
        ustack[argc] = sp;
    }
    /*
    if(argc >= 3)
        printf("\nargc %s", argv[2]);
    printf("\n %d \n", argc);
    */

    ustack[argc] = 0;

    //printf("exec 3\n");
    sp -= (argc + 1) * sizeof(uint64_t);
    sp -= sp % 16;
    if(sp < stackbase || (copyout(pagetable, sp, (char *)ustack, (argc+1)*sizeof(uint64_t)) < 0)){
        if(pagetable)
            proc_freepagetable(pagetable, sz);
        if(ip){
            iunlockput(ip);
        }
        return -1;
    }

    p->trapframe->a1 = sp;

    for(last = s = path; *s; s++){
        if(*s == '/'){
            last = s + 1;
        }
    }
    //printf("exec 4\n");
    safestrcpy(p->name, last, sizeof(p->name));

    oldpagetable = p->pagetable;
    p->pagetable = pagetable;
    p->sz = sz;
    p->trapframe->epc = elf.entry;
    p->trapframe->sp = sp;
    proc_freepagetable(oldpagetable, oldsz);

    //printf("bye exec\n");
    return argc;
}

