        de->dev = 0;
        de->valid = 0;
        de->ref = 0;
        de->dirty = 0;
        de->parent = 0;
        de->next = root.next;
        de->prev = &root;
        init_sleeplock(&de->lock, "entry");
        root.next->prev = de;
        root.next = de;
    }
