char *formatname(char *name)
{
    static char illegal[] = { '\"', '*', '/', ':', '<', '>', '?', '\\', '|', 0 };
    char *p;
    while (*name == ' ' || *name == '.') { name++; }
    for (p = name; *p; p++) {
        char c = *p;
        if (c < 0x20 || strchr(illegal, c)) {
            return 0;
        }
    }
    while (p-- > name) {
        if (*p != ' ') {
            p[1] = '\0';
            break;
        }
    }
    return name;
}

#define FAT32_EOC 0x0ffffff8    // the cluster number of end
static uint32_t read_fat(uint32_t cluster) {
    if (cluster >= FAT32_EOC) {
        return cluster;
    }
    if (cluster > fat.data_clus_cnt + 1) {     // because cluster number starts at 2, not 0
        return 0;
    }
    uint32_t fat_sec = fat_sec_of_clus(cluster, 1);
    struct buf *b = bread(0, fat_sec);                  // fat table store the next cluster number
    uint32_t next_clus = *(uint32_t *)(b->data + fat_offset_of_clus(cluster));
    brelse(b);
    return next_clus; // return the next cluster number
}

