    }
    uint32_t fat_sec = fat_sec_of_clus(cluster, 1);
    struct buf *b = bread(0, fat_sec);
    uint32_t off = fat_offset_of_clus(cluster);
    *(uint32_t *)(b->data + off) = content;
    bwrite(b);
    brelse(b);
    return 0;
}

