void binit(void){
    struct buf *b;
    initlock(&bcache.lock, "bcache");

    bcache.head.prev = &bcache.head;
    bcache.head.next = &bcache.head;
    for(b = bcache.buf; b < bcache.buf + 30; b++){
        b->refcnt = 0;
        b->sectorno = ~0;
        b->dev = ~0;
        b->next = bcache.head.next;
        b->prev = &bcache.head;
        init_sleeplock(&b->lock, "buffer"); // 为每一个buffer都申请一个睡眠锁
        bcache.head.next->prev = b;
        bcache.head.next = b;
    }

}

/* Get the same buffer as the sector number */
static struct buf* bget(uint32_t dev, uint32_t sect){
    struct buf *b;
    acquire(&bcache.lock);

    /* find */
    for(b = bcache.head.next; b != &bcache.head; b = b->next){
        if(b->dev == dev && b->sectorno == sect){
            b->refcnt ++;
            release(&bcache.lock);
            acquiresleep(&b->lock);
            return b;
        }
    }
    /* unfind */
    for(b = bcache.head.prev; b != &bcache.head; b = b->prev){
        if(! b->refcnt){
            b->dev = dev;
            b->sectorno = sect;
            b->valid = 0;
            b->refcnt = 1;
            release(&bcache.lock);
            acquiresleep(&b->lock);
            return b;
        }
    }
    //panic("bget: no buffers");
}

// read the data from disk to buffer in mem
struct buf* bread(uint32_t dev, uint32_t sect){
    struct buf *b;

    b = bget(dev, sect);
    if(! b->valid){
        virtio_disk_rw(b, 0);
        b->valid = 1;
    }
    return b;
}

// write the disk from the buffer in mem to disk
void bwrite(struct buf *b){
    /*
    if(!holdingsleep(&b->lock)){
        panic("bwrite");
    }
    */
    virtio_disk_rw(b, 1);
}

void brelse(struct buf *b){
    /*
    if(!holdingsleep(&b->lock)){
        panic("brelse");
    }
    */
    releasesleep(&b->lock);

    acquire(&bcache.lock);

    b->refcnt --;

    /* LRU : if the buffer's refcnt equal zero, put it behind head*/
    if(b->refcnt == 0){
        b->next->prev = b->prev;
        b->prev->next = b->next;
        b->next = bcache.head.next;
        b->prev = &bcache.head;
        bcache.head.next->prev = b;
        bcache.head.next = b;
    }

    release(&bcache.lock);
}

void bpin(struct buf *b) {
    acquire(&bcache.lock);
    b->refcnt++;
    release(&bcache.lock);
}

void bunpin(struct buf *b) {
    acquire(&bcache.lock);
    b->refcnt--;
    release(&bcache.lock);
}

