    struct proc *p = myproc();
    struct stat st;

    if(f->type == FD_INODE || f->type == FD_DEVICE){
        ilock(f->ip);
        stati(f->ip, &st);
        iunlock(f->ip);
        if(copyout(p->pagetable, addr, (char *)&st, sizeof(st)) < 0){
            return -1;
        }
        return 0;
    }
    return -1;
}

int fileread(struct file* f, uint64_t addr, int n){
    int r = 0;
    //printf("fileread %d\n", f->type);
    if(!f->readable){
        return -1;
    }

    if(f->type == FD_PIPE){
        r = piperead(f->pipe, addr, n);
    } else if(f->type == FD_DEVICE){
        if(f->major < 0 || f->major >= NDEV || !devsw[f->major].read){
            return -1;
        }
        r = devsw[f->major].read(1, addr, n);
    } else if(f->type == FD_INODE){
        ilock(f->ip);
        if((r = readi(f->ip, 1, addr, f->off, n)) > 0){
            f->off += r;
            //printf("readi > 0\n");
        }
        iunlock(f->ip);
    } else {
        panic("fileread");
    }
    return r;
}

int filewrite(struct file *f, uint64_t addr, int n){
    //printf("type: \n", f->type);
    int r , ret = 0;
    //printf("filewrite\n");
    if(!f->writable){
        return -1;
    }
    if(f->type == FD_PIPE){
        ret = pipewrite(f->pipe, addr, n);
    } else if(f->type == FD_DEVICE){
        if(f->major < 0 || f->major > NDEV || !devsw[f->major].write){
            return -1;
        }
        ret = devsw[f->major].write(1, addr, n);
    } else if(f->type == FD_INODE){
        ilock(f->ip);
        if(writei(f->ip, 1, addr, f->off, n) == n){
            ret = n;
            f->off += n;
        } else {
            ret -= 1;
        }
        iunlock(f->ip);
    } else {
        printf("filewrite\n");
        //panic("filewirte");
    }
    return ret;
}

#define ATTR_DIRECTORY 0x10
int dirnext(struct file *f, uint64_t addr)
{
    if(f->readable == 0 || !(f->ip->attribute & ATTR_DIRECTORY))
        return -1;
    struct dirent de;
    struct stat st;
    int count = 0;
    int ret;
    ilock(f->ip);
    while ((ret = enext(f->ip, &de, f->off, &count)) == 0) {  // skip empty entry
        f->off += count * 32;
    }
    iunlock(f->ip);
    if (ret == -1)
        return 0;

    f->off += count * 32;
    stati(&de, &st);
    if(copyout(myproc()->pagetable ,addr, (char *)&st, sizeof(st)) < 0)
        return -1;
    return 1;
}

