static struct dirent* create(char *path, short type, int mode){
    struct dirent *ip, *dp;
    char name[256];
    if((dp = nameiparent(path, name)) == 0){
        return 0;
    }

    if (type == T_DIR) {
        mode = 0x10;
    } else if (mode & O_RDONLY) {
        mode = 0x01;
    } else {
        mode = 0;  
    }
    ilock(dp);
    if ((ip = ialloc(dp, name, mode)) == NULL) {
        while(1);
        iunlock(dp);
        iput(dp);
        return NULL;
    }

    if ((type == T_DIR && !(ip->attribute & 0x10)) ||
        (type == T_FILE && (ip->attribute & 0x10))) {
        iunlock(dp);
        iput(ip);
        iput(dp);
        return NULL;
    }

    iunlock(dp);
    iput(dp);

    ilock(ip);
    return ip;
}

