}

void acquiresleep(struct sleeplock *lock){
    acquire(&lock->lock);
    while (lock->locked){
        sleep(lock, &lock->lock);   // TODO
    }

    lock->locked = 1;
    lock->pid = myproc()->pid;
    release(&lock->lock);
}

void releasesleep(struct sleeplock *lock)
{
    acquire(&lock->lock);
    lock->locked = 0;
    lock->pid = 0;
    wakeup(lock);                     // TODO
    release(&lock->lock);
}

int holdingsleep(struct sleeplock *lock)
{
    int r;
    acquire(&lock->lock);
    r = lock->locked && (lock->pid == myproc()->pid);
    release(&lock->lock);
    return r;
}

