void* memset(void *dst, int c, uint32_t n)
{
  char *cdst = (char *) dst;
  int i;
  for(i = 0; i < n; i++){
    cdst[i] = c;
  }
  return dst;
}

void *memmove(void *dst, const void *src, uint32_t n){
  const char *s;
  char *d;
  if(n == 0){
    return dst;
  }

  s = src;
  d = dst;
  if(s < d && s + n > d){
    s += n;
    d += n;
    while(n-- > 0){
      *--d = *--s;
    } 
  }else{
      while(n --){
        *d++ = *s++;
      }
    }
    return dst; 
}

int memcmp(const void *src, const void *dst, uint32_t n)
{
    const uint8_t *s1, *s2;

    s1 = src;
    s2 = dst;
    while(n-- > 0){
        if(*s1 != *s2)
            return *s1 - *s2;
        s1++, s2++;
    }

    return 0;
}

void *memcpy(void *dst, const void *src, uint32_t n){
    return memmove(dst, src, n);
}

int strncmp(const char *p, const char *q, uint32_t n){
    while(n > 0 && *p && *p == *q){
        n --;
        p ++;
        q ++;
    }
    if(n == 0){
        return 0;
    }
    return (uint8_t)*p - (uint8_t)*q;
}

char *strncpy(char *s, const char *t, int n){
    char *os;

    os = s;
    while(n-- > 0 ){
        *s++ = *t++;
    }
    return os;
}

char* safestrcpy(char *s, const char *t, int n)
{
  char *os;

  os = s;
  if(n <= 0)
    return os;
  while(--n > 0 && (*s++ = *t++) != 0)
    ;
  *s = 0;
  return os;
}

int strlen(const char *s)
{
  int n;
  for( n = 0; s[n]; n++);

  return n;
}

// convert uint8_t string into wide char string 
void wnstr(uint16_t *dst, char const *src, int len) {
  while (len -- && *src) {
    *(uint8_t*)dst = *src++;
    dst ++;
  }

  *dst = 0;
}

// convert wide char string into uint8_t string 
void snstr(char *dst, uint16_t const *src, int len) {
  while (len -- && *src) {
    *dst++ = (uint8_t)(*src & 0xff);
    src ++;
  }
  while(len-- > 0)
    *dst++ = 0;
}

int wcsncmp(uint16_t const *s1, uint16_t const *s2, int len) {
  int ret = 0;

  while (len-- && *s1) {
    ret = (int)(*s1++ - *s2++);
    if (ret) break;
  }

  return ret;
}

